-- ===================== Specs pour quelques produits cles =====================
SELECT id, 'processor', 'Apple M4 (10-core CPU, 10-core GPU)', 1 FROM catalog_products WHERE slug LIKE 'macbook-air-13-m4-16-256%'
UNION ALL
SELECT id, 'display', '13.6" Liquid Retina, 2560x1664', 2 FROM catalog_products WHERE slug LIKE 'macbook-air-13-m4-16-256%'
UNION ALL
SELECT id, 'battery', 'Jusqu''a 18 heures', 3 FROM catalog_products WHERE slug LIKE 'macbook-air-13-m4-16-256%'
UNION ALL
SELECT id, 'weight', '1.24 kg', 4 FROM catalog_products WHERE slug LIKE 'macbook-air-13-m4-16-256%'
UNION ALL
SELECT id, 'processor', 'Apple M4 Pro (14-core CPU, 20-core GPU)', 1 FROM catalog_products WHERE slug LIKE 'macbook-pro-14-m4pro%'
UNION ALL
SELECT id, 'display', '14.2" Liquid Retina XDR, 3024x1964, ProMotion 120Hz', 2 FROM catalog_products WHERE slug LIKE 'macbook-pro-14-m4pro%'
UNION ALL
SELECT id, 'battery', 'Jusqu''a 24 heures', 3 FROM catalog_products WHERE slug LIKE 'macbook-pro-14-m4pro%'
UNION ALL
SELECT id, 'processor', 'Apple M4 (10-core CPU, 10-core GPU)', 1 FROM catalog_products WHERE slug LIKE 'imac-24-m4%'
UNION ALL
SELECT id, 'display', '24" Retina 4.5K, 4480x2520', 2 FROM catalog_products WHERE slug LIKE 'imac-24-m4%'
UNION ALL
SELECT id, 'processor', 'Apple M4 (10-core CPU, 10-core GPU)', 1 FROM catalog_products WHERE slug LIKE 'mac-mini-m4-16%' OR slug LIKE 'mac-mini-m4-24%'
UNION ALL
SELECT id, 'processor', 'Apple M4 Pro (14-core CPU, 20-core GPU)', 1 FROM catalog_products WHERE slug LIKE 'mac-mini-m4pro%'
UNION ALL
SELECT id, 'processor', 'Apple M4 Max (16-core CPU, 40-core GPU)', 1 FROM catalog_products WHERE slug LIKE 'mac-studio-m4max%'
UNION ALL
SELECT id, 'processor', 'Apple M4 Ultra (32-core CPU, 80-core GPU)', 1 FROM catalog_products WHERE slug LIKE 'mac-studio-m4ultra%'
UNION ALL
SELECT id, 'processor', 'Apple M2 Ultra (24-core CPU, 76-core GPU)', 1 FROM catalog_products WHERE slug LIKE 'mac-pro%';
